        __m256d p2r=_mm256_fnmadd_pd(cA,sd_r,t0r), p2i=_mm256_fnmadd_pd(cA,sd_i,t0i);
        __m256d qar=_mm256_fmadd_pd(cC,d2i,_mm256_mul_pd(cB,d1i)), qai=_mm256_fmadd_pd(cC,d2r,_mm256_mul_pd(cB,d1r));
